CREATE TABLE IF NOT EXISTS warehouse_transfers(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),transfer_no text NOT NULL,source_warehouse_id uuid NOT NULL REFERENCES warehouses(id),target_warehouse_id uuid NOT NULL REFERENCES warehouses(id),status text NOT NULL DEFAULT'draft'CHECK(status IN('draft','in_transit','received','cancelled','reversed')),out_document_id uuid REFERENCES stock_documents(id),in_document_id uuid REFERENCES stock_documents(id),created_by uuid REFERENCES users(id),dispatched_at timestamptz,received_at timestamptz,created_at timestamptz NOT NULL DEFAULT now(),UNIQUE(source_warehouse_id,transfer_no),CHECK(source_warehouse_id<>target_warehouse_id));
CREATE TABLE IF NOT EXISTS warehouse_transfer_lines(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),transfer_id uuid NOT NULL REFERENCES warehouse_transfers(id)ON DELETE CASCADE,source_balance_id uuid NOT NULL REFERENCES stock_balances(id),source_product_id uuid NOT NULL REFERENCES products(id),target_product_id uuid NOT NULL REFERENCES products(id),source_location_id uuid NOT NULL REFERENCES locations(id),target_location_id uuid REFERENCES locations(id),lot_code text,serial_code text,manufactured_at date,expires_at date,quantity numeric(18,4)NOT NULL CHECK(quantity>0));
CREATE INDEX IF NOT EXISTS idx_transfers_source ON warehouse_transfers(source_warehouse_id,status,created_at DESC);CREATE INDEX IF NOT EXISTS idx_transfers_target ON warehouse_transfers(target_warehouse_id,status,created_at DESC);
